import paddle
import paddle.nn as nn

class SimpleNet(nn.Layer):
    def __init__(self):
        super().__init__()
        self.fc = nn.Linear(784, 10)

    def forward(self, x):
        return self.fc(x)

model = SimpleNet()
x = paddle.randn([32, 784])
y = model(x)
print(y.shape)

